import React, { useEffect, useState } from 'react';
import api from '../api';

const PatientList = () => {
  const [patients, setPatients] = useState<any[]>([]);

  useEffect(() => {
    api.get('patients/')
      .then((res: any) => setPatients(res.data))
      .catch((err: any) => console.error("Error fetching patients:", err));
  }, []);

  return (
    <div className="overflow-x-auto bg-white rounded-xl shadow-md border border-gray-100">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Patient Name</th>
            <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Email</th>
            <th className="px-6 py-4 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">Actions</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {patients.map((p: any) => (
            <tr key={p.patient_id} className="hover:bg-blue-50/50 transition-colors">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-800">{p.full_name}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">{p.email}</td>
              <td className="px-6 py-4 text-center space-x-2">
                <button className="text-blue-600 hover:text-blue-800 font-semibold text-sm">Edit</button>
                <button className="text-red-600 hover:text-red-800 font-semibold text-sm">Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default PatientList;
